export const DEFAULT_STAMP_DATA_URL = "data:image/png;base64,";

export function formatBusinessNumber(value) {
  const digits = String(value || "").replace(/\D/g, "").slice(0, 10);

  if (digits.length <= 3) return digits;
  if (digits.length <= 5) return `${digits.slice(0, 3)}-${digits.slice(3)}`;
  return `${digits.slice(0, 3)}-${digits.slice(3, 5)}-${digits.slice(5)}`;
}

export function isValidBusinessNumber(value) {
  return String(value || "").replace(/\D/g, "").length === 10;
}

export function imageFileToDataUrl(file, maxSide = 600, quality = 0.86) {
  return new Promise((resolve, reject) => {
    if (!file?.type?.startsWith("image/")) {
      reject(new Error("이미지 파일만 선택할 수 있습니다."));
      return;
    }

    const image = new Image();
    const reader = new FileReader();

    reader.onload = () => {
      image.onload = () => {
        const scale = Math.min(1, maxSide / Math.max(image.width, image.height));
        const width = Math.max(1, Math.round(image.width * scale));
        const height = Math.max(1, Math.round(image.height * scale));
        const canvas = document.createElement("canvas");
        canvas.width = width;
        canvas.height = height;

        const context = canvas.getContext("2d");
        context.clearRect(0, 0, width, height);
        context.drawImage(image, 0, 0, width, height);

        resolve(canvas.toDataURL("image/png", quality));
      };

      image.onerror = () => reject(new Error("직인 이미지를 읽지 못했습니다."));
      image.src = reader.result;
    };

    reader.onerror = () => reject(new Error("직인 파일을 읽지 못했습니다."));
    reader.readAsDataURL(file);
  });
}
